"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[38348],{92815(e,t,n){n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>h,frontMatter:()=>s,metadata:()=>i,toc:()=>l});let i=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments/physical-settlement-of-contracts-to--8e19b89d27","title":"Physical Settlement of Contracts to Buy or Sell a Non-financial Item (IFRS 9)","description":"March 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments/Physical Settlement of Contracts to Buy or Sell a Non-financial Item (IFRS 9).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/physical-settlement-of-contracts-to--8e19b89d27","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/physical-settlement-of-contracts-to--8e19b89d27","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":5,"frontMatter":{"id":"physical-settlement-of-contracts-to--8e19b89d27","title":"Physical Settlement of Contracts to Buy or Sell a Non-financial Item (IFRS 9)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/physical-settlement-of-contracts-to--8e19b89d27","sidebar_position":5},"sidebar":"knowledgeSidebar","previous":{"title":"Hedging Variability in Cash Flows due to Real Interest Rates (IFRS 9)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/hedging-variability-in-cash-flows-du-5d82ceea22"},"next":{"title":"Lessor Forgiveness of Lease Payments (IFRS 9 and IFRS 16)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-and-ifr-f215bc1791/lessor-forgiveness-of-lease-payments-c873b0bd71"}}');var a=n(74848),o=n(28453);let s={id:"physical-settlement-of-contracts-to--8e19b89d27",title:"Physical Settlement of Contracts to Buy or Sell a Non-financial Item (IFRS 9)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/physical-settlement-of-contracts-to--8e19b89d27",sidebar_position:5},r="Physical Settlement of Contracts to Buy or Sell a Non-financial Item (IFRS 9)",c={},l=[];function d(e){let t={h1:"h1",header:"header",p:"p",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"physical-settlement-of-contracts-to-buy-or-sell-a-non-financial-item-ifrs-9",children:"Physical Settlement of Contracts to Buy or Sell a Non-financial Item (IFRS 9)"})}),"\n",(0,a.jsx)(t.p,{children:"March 2019"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about how an entity applies IFRS 9 to particular contracts to buy or sell a non-financial item in the future at a fixed price. The request describes two fact patterns in which an entity accounts for such contracts as derivatives at fair value through profit or loss (FVPL) but nonetheless physically settles the contracts by either delivering or taking delivery of the underlying non-financial item."}),"\n",(0,a.jsx)(t.p,{children:"IFRS 9 must be applied to contracts to buy or sell a non-financial item that can be settled net in cash or another financial instrument, or by exchanging financial instruments, as if those contracts were financial instruments, with one exception. That exception applies to contracts that were entered into and continue to be held for the purpose of the receipt or delivery of a non-financial item in accordance with the entity\u2019s expected purchase, sale or\nusage requirements (\u2018own use scope exception\u2019 in paragraph 2.4 of IFRS 9)."}),"\n",(0,a.jsx)(t.p,{children:"In the fact patterns described in the request, the entity concludes that the contracts are within the scope of IFRS 9 because they do not meet the own use scope exception. Consequently, the entity accounts for the contracts as derivatives measured at FVPL. The entity does not designate the contracts as part of a hedging relationship for accounting purposes."}),"\n",(0,a.jsx)(t.p,{children:"At the settlement date, the entity physically settles the contracts by either delivering or taking delivery of the non-financial item. In accounting for that settlement, the request explains that the entity records the cash paid (in the case of the purchase contract) or received (in the case of the sale contract) and derecognises the derivative."}),"\n",(0,a.jsx)(t.p,{children:"In addition, the entity:"}),"\n",(0,a.jsx)(t.p,{children:"a. recognises inventory for the non-financial item at the amount of the cash paid plus the fair value of the derivative on the settlement date (in the case of the purchase contract); or"}),"\n",(0,a.jsx)(t.p,{children:"b. recognises revenue for the sale of the non-financial item at the amount of the cash received plus the fair value of the derivative on the settlement date (in the case of the sale contract). The request assumes the entity has an accounting policy of recognising revenue on a gross basis for such contracts."}),"\n",(0,a.jsx)(t.p,{children:"The request asked whether, in accounting for the physical settlement of these contracts, the entity is permitted or required to make an additional journal entry that would:"}),"\n",(0,a.jsx)(t.p,{children:"a. reverse the accumulated gain or loss previously recognised in profit or loss on the derivative (even though the fair value of the derivative is unchanged); and\nb. recognise a corresponding adjustment to either revenue (in the case of the sale contract) or inventory (in the case of the purchase contract)."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, in the fact patterns described in the request, the contracts are settled by the receipt (or delivery) of a non-financial item in exchange for both cash and the settlement of the derivative asset or liability. The Committee also observed that the accounting for contracts that do not meet the own use scope exception in IFRS 9 (and are accounted for as a derivative) is different from the accounting for contracts that meet that exception (and are not accounted for as a derivative). Similarly, the accounting for contracts designated in a hedging relationship for accounting purposes is different from the accounting for contracts that are not designated in such relationships. Those differences in accounting reflect differences in the respective requirements. IFRS 9 neither permits nor requires an entity to reassess or change its accounting for a derivative contract because that contract is ultimately physically settled."}),"\n",(0,a.jsx)(t.p,{children:"The additional journal entry described in the request would effectively negate the requirement in IFRS 9 to account for the contract as a derivative because it would reverse the accumulated fair value gain or loss on the derivative without any basis to do so. The additional journal entry would also result in the recognition of income or expenses on the derivative that do not exist."}),"\n",(0,a.jsx)(t.p,{children:"Consequently, the Committee concluded that IFRS 9 neither permits nor requires an entity to make the additional journal entry described in the request. However, the Committee observed that an entity is required to present gains and losses on the derivative, and disclose information about those amounts, applying applicable IFRS Standards, such as IAS 1 Presentation of Financial Statements and IFRS 7 Financial Instruments: Disclosures. In determining what line items to present in profit or loss, the requirements in IAS 1 (including those related to aggregation) are applicable. IAS 1 does not specify requirements for the presentation of amounts related to the remeasurement of derivatives. However paragraph 20(a)(i) of IFRS 7 specifies disclosure requirements for net gains or net losses on financial assets or financial liabilities that are mandatorily measured at FVPL applying IFRS 9. For these purposes, in the fact patterns described in the request, there is no gain or loss on the derivative caused by settlement."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Standards provide an adequate basis for an entity to conclude on whether it is permitted or required to make the additional journal entry described in the request. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function h(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},28453(e,t,n){n.d(t,{R:()=>s,x:()=>r});var i=n(96540);let a={},o=i.createContext(a);function s(e){let t=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(o.Provider,{value:t},e.children)}}}]);